module aaoi(egress,in1,in2,in3,in4);
   
   output egress;
   input  in1;
   input  in2;
   input  in3;
   input  in4;

   assign egress = !(in1&in2) & !(in3&in4);   

endmodule // aaoi


module halfAdd(cout,s,a,b);
   
   output cout;
   output s;
   input  a;
   input  b;
   
   and2 carryComp0_0(cout,a,b);
   xor2 sumComp_0_40(a,b,s);
   
endmodule // halfAdd


// booth_encoder_r4 takes in X[2:0], which corresponds to X_(2n-1) to X_(2n+1)
// it outputs control signals to a Booth selector that cause the selector to
// send out the correct partial product

module r4bs(y1,y0,sing,doub,neg,pp); 
   
   input  y1;
   input  y0;
   input  sing;
   input  doub;
   input  neg;
   output pp;

   wire   aaoiRes;

   aaoi   usppgen_0_0(aaoiRes,doub,y1,sing,y0);
   xnor2  ppinverter_0_40(aaoiRes,neg,pp);
   
endmodule // r4bs


module r4be(x0,x1,x2,sing,doub,neg);
   
   input x0;
   input x1;
   input x2;
   output sing;
   output doub;
   output neg;

   wire   singRes;
   wire   doubRes;

   wire   x0b;
   wire   x1b;
   wire   x2b;

   wire   nandaRes;
   wire   nandbRes;

   assign neg = x2;   
   assign sing = x0^x1;   
   assign x0b = ~x0;
   assign x1b = ~x1;
   assign x2b = ~x2;   

   // Nand structure = see Bewick
   assign nandaRes = ~(x0 & x1 & x2b);
   assign nandbRes = ~(x0b & x1b & x2);
   assign doub = ~(nandaRes & nandbRes);
   
endmodule // r4be


// Use maj and two xor2's, with cin being late
module fullAdd_xc(cout, s, a, b, cin);
   
   output cout;
   output s;
   input  a;
   input  b;
   input  cin;

   wire   xorRes;

   xor2  XOR1_0_0(a,b,xorRes);
   xor2  XOR2_0_56(xorRes,cin,s);
   maj   MAJ_0_112(cout,a,b,cin);
   
endmodule // fullAdd_xc


module maj(y, a, b, c);
   
   output y;
   input  a;
   input  b;
   input  c;

   wire   min;

   min mincomp_0_0(min,a,b,c);
   inverter outinv_0_32(y,min);
   
endmodule // maj


// 4:2 Weinberger compressor
module fourtwo_x(t, S, C, X, Y, Z, W, t_1);
   
   output t;//fast cout
   output S;
   output C;//slow cout
   
   input  X;//two xor delays to s
   input  Y;//three xor delays to s
   input  Z;//three xor delays to s
   input  W;//two xor delays to s
   input  t_1;//two xor delayts to s

   wire   intermediate;

   fullAdd_xc firstCSA_0_0(t,intermediate,Y,Z,X);
   fullAdd_xc secondCSA_0_160(C,S,W,t_1,intermediate);
   
endmodule // fourtwo_x


