module xor2(a,b,y);
   input a;
   input b;
   output y;

   wire   a_b;
   wire   b_b;


   inverter inva_0_0(a_b,a);
   inverter invb_0_16(b_b,b);

   subxor sub_0_32(y,a,a_b,b,b_b);

endmodule // xor2


